changeSet.sql:
CREATE TABLE risk_model_item_comments
(
	id serial,
	risk_model_id Integer NOT NULL,
	item_type_name character varying (128) DEFAULT NULL,
	external_id Integer NOT NULL,
	external_uid character varying (64) DEFAULT NULL,
	comment text DEFAULT NULL,
	created_at timestamp without time zone DEFAULT now(),
	updated_at timestamp without time zone DEFAULT now(),

	CONSTRAINT pk_risk_model_item_comments_id PRIMARY KEY (id),
	CONSTRAINT fk_risk_model_item_comments_to_risk_model FOREIGN KEY (risk_model_id) REFERENCES risk_models (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE CASCADE
);
CREATE INDEX i_risk_model_item_comments_risk_model_id ON risk_model_item_comments (risk_model_id);
CREATE INDEX i_risk_model_item_comments_external_id ON risk_model_item_comments (external_id);
CREATE INDEX i_risk_model_item_comments_external_uid ON risk_model_item_comments (external_uid);
CREATE INDEX i_risk_model_item_comments_item_type_name ON risk_model_item_comments (item_type_name);
CREATE INDEX i_risk_model_item_comments_risk_model_item_type_name ON risk_model_item_comments (risk_model_id, item_type_name);
